@* Displays a single product as a card with image, name, price, rating, stock badge, and add-to-cart *@

<div class="product-card" @onclick="HandleCardClick">
    <div class="product-image" role="img" aria-label="@Product.Name">
        @Product.Name
    </div>

    <div class="product-info">
        <h3 class="product-name" title="@Product.Name">@Product.Name</h3>
        <p class="product-price">@Product.Price.ToString("C")</p>
        <div class="product-rating" title="@($"{Product.Rating:F1} out of 5")">
            @GetStarDisplay(Product.Rating)
        </div>

        @if (!Product.InStock)
        {
            <span class="badge-out-of-stock">Out of Stock</span>
        }

        <button class="btn-add-to-cart"
                disabled="@(!Product.InStock)"
                @onclick="HandleAddToCart"
                @onclick:stopPropagation="true">
            Add to Cart
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public Product Product { get; set; } = default!;

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }

    private async Task HandleCardClick()
    {
        await OnProductSelected.InvokeAsync(Product);
    }

    private async Task HandleAddToCart()
    {
        if (Product.InStock)
        {
            await OnAddToCart.InvokeAsync(Product);
        }
    }

    private static string GetStarDisplay(double rating)
    {
        int filled = (int)Math.Round(rating);
        return new string('★', filled) + new string('☆', 5 - filled);
    }
}

@* Renders a responsive grid of ProductCard components *@

@if (Products is null || !Products.Any())
{
    <div class="empty-results">
        <p>No products found matching your criteria.</p>
    </div>
}
else
{
    <div class="product-grid">
        @foreach (var product in Products)
        {
            <ProductCard Product="product"
                         OnProductSelected="OnProductSelected"
                         OnAddToCart="OnAddToCart" />
        }
    </div>
}

@code {
    [Parameter, EditorRequired]
    public List<Product> Products { get; set; } = [];

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }
}

@* Left sidebar with category checkboxes, price range inputs, stock toggle, and apply/clear buttons *@

<aside class="catalog-sidebar">
    <h2>Filters</h2>

    <div class="filter-section">
        <h3>Categories</h3>
        @if (Categories is not null)
        {
            @foreach (var category in Categories)
            {
                <label class="filter-checkbox">
                    <input type="checkbox"
                           checked="@IsSelected(category)"
                           @onchange="@(e => ToggleCategory(category, (bool)e.Value!))" />
                    @category
                </label>
            }
        }
    </div>

    <div class="filter-section">
        <h3>Price Range</h3>
        <div class="price-inputs">
            <label>
                Min
                <input type="number" min="0" step="0.01"
                       value="@_minPrice"
                       @onchange="@(e => _minPrice = ParseDecimal(e.Value))" />
            </label>
            <label>
                Max
                <input type="number" min="0" step="0.01"
                       value="@_maxPrice"
                       @onchange="@(e => _maxPrice = ParseDecimal(e.Value))" />
            </label>
        </div>
    </div>

    <div class="filter-section">
        <label class="filter-checkbox">
            <input type="checkbox" @bind="_inStockOnly" />
            In Stock Only
        </label>
    </div>

    <div class="filter-actions">
        <button class="btn-apply" @onclick="ApplyFilters">Apply Filters</button>
        <button class="btn-clear" @onclick="ClearFilters">Clear Filters</button>
    </div>
</aside>

@code {
    [Parameter, EditorRequired]
    public List<string> Categories { get; set; } = [];

    [Parameter]
    public EventCallback<ProductFilter> OnFilterApplied { get; set; }

    [Parameter]
    public EventCallback OnFilterCleared { get; set; }

    private List<string> _selectedCategories = [];
    private decimal? _minPrice;
    private decimal? _maxPrice;
    private bool _inStockOnly;

    private bool IsSelected(string category) => _selectedCategories.Contains(category);

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
        {
            if (!_selectedCategories.Contains(category))
                _selectedCategories.Add(category);
        }
        else
        {
            _selectedCategories.Remove(category);
        }
    }

    private async Task ApplyFilters()
    {
        var filter = new ProductFilter(
            Categories: _selectedCategories.Count > 0 ? new List<string>(_selectedCategories) : null,
            MinPrice: _minPrice,
            MaxPrice: _maxPrice,
            InStockOnly: _inStockOnly
        );
        await OnFilterApplied.InvokeAsync(filter);
    }

    private async Task ClearFilters()
    {
        _selectedCategories = [];
        _minPrice = null;
        _maxPrice = null;
        _inStockOnly = false;
        await OnFilterCleared.InvokeAsync();
    }

    private static decimal? ParseDecimal(object? value)
    {
        if (value is null || string.IsNullOrWhiteSpace(value.ToString()))
            return null;
        return decimal.TryParse(value.ToString(), out var result) ? result : null;
    }
}

@* Toolbar with sort dropdown and result count display *@

<div class="catalog-toolbar">
    <div class="sort-control">
        <label for="sort-select">Sort by:</label>
        <select id="sort-select" value="@SortBy" @onchange="HandleSortChange">
            <option value="price_asc">Price: Low to High</option>
            <option value="price_desc">Price: High to Low</option>
            <option value="name_asc">Name: A-Z</option>
            <option value="rating_desc">Rating: Highest</option>
        </select>
    </div>

    <div class="result-count">
        @if (TotalCount > 0)
        {
            var first = (Page - 1) * PageSize + 1;
            var last = Math.Min(Page * PageSize, TotalCount);
            <span>Showing @first–@last of @TotalCount products</span>
        }
        else
        {
            <span>No products found</span>
        }
    </div>
</div>

@code {
    [Parameter] public string SortBy { get; set; } = "price_asc";
    [Parameter] public int TotalCount { get; set; }
    [Parameter] public int Page { get; set; } = 1;
    [Parameter] public int PageSize { get; set; } = 12;
    [Parameter] public EventCallback<string> OnSortChanged { get; set; }

    private async Task HandleSortChange(ChangeEventArgs e)
    {
        await OnSortChanged.InvokeAsync(e.Value?.ToString() ?? "price_asc");
    }
}

@* Pagination controls: Previous, numbered pages, Next *@

@if (TotalPages > 1)
{
    <nav class="catalog-pagination" aria-label="Product pagination">
        <button class="page-btn"
                disabled="@(CurrentPage <= 1)"
                @onclick="@(() => GoToPage(CurrentPage - 1))">
            Previous
        </button>

        @foreach (var page in GetPageNumbers())
        {
            <button class="page-btn @(page == CurrentPage ? "active" : "")"
                    @onclick="@(() => GoToPage(page))">
                @page
            </button>
        }

        <button class="page-btn"
                disabled="@(CurrentPage >= TotalPages)"
                @onclick="@(() => GoToPage(CurrentPage + 1))">
            Next
        </button>
    </nav>
}

@code {
    [Parameter] public int CurrentPage { get; set; } = 1;
    [Parameter] public int TotalPages { get; set; } = 1;
    [Parameter] public EventCallback<int> OnPageChanged { get; set; }

    private async Task GoToPage(int page)
    {
        if (page >= 1 && page <= TotalPages && page != CurrentPage)
        {
            await OnPageChanged.InvokeAsync(page);
        }
    }

    private IEnumerable<int> GetPageNumbers()
    {
        // Show up to 7 page numbers, centered around current page
        const int maxVisible = 7;
        int start, end;

        if (TotalPages <= maxVisible)
        {
            start = 1;
            end = TotalPages;
        }
        else
        {
            int half = maxVisible / 2;
            start = Math.Max(1, CurrentPage - half);
            end = start + maxVisible - 1;
            if (end > TotalPages)
            {
                end = TotalPages;
                start = end - maxVisible + 1;
            }
        }

        for (int i = start; i <= end; i++)
            yield return i;
    }
}

@page "/catalog"
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<h1>Product Catalog</h1>

@if (_error is not null)
{
    <div class="catalog-error">
        <p>Something went wrong: @_error</p>
        <button class="btn-apply" @onclick="LoadProductsAsync">Retry</button>
    </div>
}
else
{
    <div class="catalog-layout">
        <CatalogSidebar Categories="_categories"
                        OnFilterApplied="HandleFilterApplied"
                        OnFilterCleared="HandleFilterCleared" />

        <div class="catalog-main">
            <CatalogToolbar SortBy="@_sortBy"
                            TotalCount="_totalCount"
                            Page="_currentPage"
                            PageSize="_pageSize"
                            OnSortChanged="HandleSortChanged" />

            @if (_loading)
            {
                <div class="catalog-loading">
                    <p>Loading products…</p>
                </div>
            }
            else
            {
                <ProductGrid Products="_products"
                             OnProductSelected="HandleProductSelected"
                             OnAddToCart="HandleAddToCart" />

                <CatalogPagination CurrentPage="_currentPage"
                                   TotalPages="_totalPages"
                                   OnPageChanged="HandlePageChanged" />
            }
        </div>
    </div>
}

@code {
    private List<Product> _products = [];
    private List<string> _categories = [];
    private ProductFilter _filter = new(null, null, null, false);
    private string _sortBy = "price_asc";
    private int _currentPage = 1;
    private int _totalCount;
    private int _totalPages;
    private const int _pageSize = 12;
    private bool _loading = true;
    private string? _error;

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }

    protected override async Task OnInitializedAsync()
    {
        try
        {
            var categoriesTask = ProductService.GetCategoriesAsync();
            var productsTask = ProductService.SearchAsync(_filter, _sortBy, _currentPage, _pageSize);

            await Task.WhenAll(categoriesTask, productsTask);

            _categories = await categoriesTask;
            ApplyResult(await productsTask);
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task HandleFilterApplied(ProductFilter filter)
    {
        _filter = filter;
        _currentPage = 1;
        await LoadProductsAsync();
    }

    private async Task HandleFilterCleared()
    {
        _filter = new ProductFilter(null, null, null, false);
        _currentPage = 1;
        await LoadProductsAsync();
    }

    private async Task HandleSortChanged(string sortBy)
    {
        _sortBy = sortBy;
        _currentPage = 1;
        await LoadProductsAsync();
    }

    private async Task HandlePageChanged(int page)
    {
        _currentPage = page;
        await LoadProductsAsync();
    }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private async Task HandleAddToCart(Product product)
    {
        await OnAddToCart.InvokeAsync(product);
    }

    private async Task LoadProductsAsync()
    {
        _loading = true;
        _error = null;

        try
        {
            var result = await ProductService.SearchAsync(_filter, _sortBy, _currentPage, _pageSize);
            ApplyResult(result);
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private void ApplyResult(PagedResult<Product> result)
    {
        _products = result.Items;
        _totalCount = result.TotalCount;
        _totalPages = (int)Math.Ceiling((double)result.TotalCount / result.PageSize);
    }
}

